def histogram(test):
    """Given a string representing a space separated uppercase letters, return a dictionary
    of the letter with the least repetition and the corresponding count.
    If all letters have the same occurrence, return only the first letter.

    Example:
    histogram('A B C') == {'A': 1}
    histogram('A B B A') == {'B': 1}
    histogram('A B C A B') == {'A': 1}
    histogram('B B B B A') == {'A': 1}
    histogram('') == {'A': 0}

    """
    if not test:
        return {'A': 0}

    # Split the string into a list of letters
    letters = test.split()

    # Create a frequency dictionary
    frequency = {}
    for letter in letters:
        if letter in frequency:
            frequency[letter] += 1
        else:
            frequency[letter] = 1

    # Find the minimum frequency
    min_count = min(frequency.values())

    # Create a result dictionary for the letters with the minimum frequency
    result = {letter: count for letter, count in frequency.items() if count == min_count}

    return result
